import{_ as a,o as t,c as s,ae as r}from"./chunks/framework.CiBL6oPQ.js";const u=JSON.parse('{"title":"Clean Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/clean-architecture.md","filePath":"architecture/clean-architecture.md"}'),n={name:"architecture/clean-architecture.md"};function o(i,e,c,l,h,p){return t(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="clean-architecture" tabindex="-1">Clean Architecture <a class="header-anchor" href="#clean-architecture" aria-label="Permalink to &quot;Clean Architecture&quot;">​</a></h1><p>The <strong>Clean Architecture</strong> (or Hexagonal Architecture) is designed to separate business rules from the infrastructure and UI. This ensures that the core domain logic is independent of external frameworks like Express, Mongoose, or Kafka.</p><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── domain/                 # Core business entities</span></span>
<span class="line"><span>├── usecases/               # Application-specific business rules</span></span>
<span class="line"><span>├── interfaces/             # Controllers, Routes, GraphQL resolvers (Adapters)</span></span>
<span class="line"><span>├── infrastructure/         # External tools (DB, Cache, Kafka, Webserver)</span></span>
<span class="line"><span>└── index.ts                # Application entry point</span></span></code></pre></div><h2 id="layers-of-dependency" tabindex="-1">Layers of Dependency <a class="header-anchor" href="#layers-of-dependency" aria-label="Permalink to &quot;Layers of Dependency&quot;">​</a></h2><ol><li><strong>Domain</strong>: Contains entities and business logic used across the application. It has zero dependencies on other layers.</li><li><strong>Use Cases</strong>: Defines application-specific actions (e.g., <code>CreateUser</code>, <code>ProcessPayment</code>). It interacts with <strong>Domain</strong> and defines <strong>Repository Interfaces</strong>.</li><li><strong>Interfaces</strong>: Bridges the external world (HTTP, Kafka) to <strong>Use Cases</strong>. For example, a REST controller transforms a request into a call for a <strong>Use Case</strong>.</li><li><strong>Infrastructure</strong>: Implements database repository interfaces, handles environment configuration, and manages the webserver.</li></ol><h2 id="why-choose-clean-architecture" tabindex="-1">Why choose Clean Architecture? <a class="header-anchor" href="#why-choose-clean-architecture" aria-label="Permalink to &quot;Why choose Clean Architecture?&quot;">​</a></h2><ul><li><strong>Framework Independent</strong>: You can change your DB or web framework with minimal effort.</li><li><strong>Testable</strong>: Business logic can be tested in isolation without mocks for the database or webserver.</li><li><strong>Maintainable</strong>: Clear separation makes it easier for large teams to work on different parts of the system.</li></ul>`,8)])])}const f=a(n,[["render",o]]);export{u as __pageData,f as default};
